function AppPersist {
    [CmdletBinding()]
    param (
        [string]$currentVersion = "3.0.0",
        [string]$savDir = $global:savDir,
        [string]$FileDir = $global:FileDir
    )

    $fileName = "rtts.app.cfg.json"
    $filePath = Join-Path -Path $FileDir -ChildPath $fileName

    # 1. Load or Initialize Data
    if (Test-Path $filePath) {
        try {
            $data = Get-Content $filePath -Raw | ConvertFrom-Json -ErrorAction Stop
            $data.RunCount++
            $data.LastBootDate = (Get-Date -Format "yyyy-MM-dd HH:mm:ss")
            # Sync global var from saved config
            if ($data.FilesDirectory) { $global:savDir = $data.FilesDirectory }
        } catch {
            Write-Warning "Config corrupted. Re-initializing."
            $data = $null
        }
    }

    if ($null -eq $data) {
        $data = [PSCustomObject]@{
            Version        = $currentVersion
            UserName       = $env:USERNAME
            FirstBootDate  = (Get-Date -Format "yyyy-MM-dd HH:mm:ss")
            LastBootDate   = (Get-Date -Format "yyyy-MM-dd HH:mm:ss")
            RunCount       = 1
            FilesDirectory = $savDir 
            AppDirectory   = $FileDir
        }
    }

    # 2. First Run Logic (Path Selection)
    if ($data.RunCount -eq 1) {
        Write-Host "First time setup detected!" -ForegroundColor Green
        if (Get-Command savDir_p -ErrorAction SilentlyContinue) {
            savDir_p
            $data.FilesDirectory = $global:savDir
        }
    }

    # 3. Final Save (Only save once)
    $data | ConvertTo-Json | Set-Content $filePath
    Write-Host "Running Persistence Check for $($data.UserName)..." -ForegroundColor Cyan

    # 4. Trial Expiry Check
    if ($data.RunCount -ge 50) {
        Add-Type -AssemblyName System.Windows.Forms
        
        $popup = New-Object System.Windows.Forms.Form
        $popup.Text = "Trial Expired"
        $popup.Size = "400, 150"
        $popup.StartPosition = "CenterScreen"
        $popup.BackColor = "#1e1e1e"
        $popup.FormBorderStyle = "FixedToolWindow"
        $popup.Topmost = $true

        $label = New-Object System.Windows.Forms.Label
        $label.Text = "Trial Expired - Contact Developer.`nClosing application..."
        $label.ForeColor = "Red"
        $label.Font = New-Object System.Drawing.Font("Segoe UI", 12, [System.Drawing.FontStyle]::Bold)
        $label.Dock = "Fill"
        $label.TextAlign = "MiddleCenter"
        $popup.Controls.Add($label)

        # 1. Ensure the popup is assigned to the script scope so the Timer can "see" it
$script:popup = $Form  # Replace $Form with whatever your popup object variable is named

# Timer to close the UI
$timer = New-Object System.Windows.Forms.Timer
$timer.Interval = 5000
$timer.add_Tick({
    # 2. Reference the script-scoped variable here
    if ($null -ne $script:popup) {
        $script:popup.Close()
        $timer.Stop() # 3. Best practice: Stop the timer once it has fired
    }
})

$timer.Start()

# 4. Use the scoped variable to show the dialog
[void]$script:popup.ShowDialog()

Write-Host "Trial expired. Exiting..." -ForegroundColor Red
exit

    }

    return $data
}
