function savDir_p {
    Add-Type -AssemblyName System.Windows.Forms
    Add-Type -AssemblyName System.Drawing

    if (-not $FileDir) { $FileDir = $PSScriptRoot } 
    $configPath = Join-Path $FileDir "rtts.app.cfg.json"

    $configData = @{}
    if (Test-Path $configPath) {
        try {
            $content = Get-Content $configPath -Raw
            if (-not [string]::IsNullOrWhiteSpace($content)) {
                $configData = $content | ConvertFrom-Json -AsHashtable
                if ($configData.ContainsKey('savDir')) { $global:savDir = $configData.savDir }
            }
        } catch { }
    }
    
    $sdform = New-Object System.Windows.Forms.Form
    $sdform.Text = "Directory Setup"
    $sdform.Size = New-Object System.Drawing.Size(450, 180)
    $sdform.StartPosition = "CenterScreen"
    $sdform.FormBorderStyle = "FixedToolWindow"
    # FORCES WINDOW TO TOP
    $sdform.Topmost = $true
    
    $label = New-Object System.Windows.Forms.Label
    $label.Size = New-Object System.Drawing.Size(400, 40)
    $label.Location = New-Object System.Drawing.Point(20, 20)
    $label.TextAlign = "MiddleCenter"
    $label.Font = New-Object System.Drawing.Font("Segoe UI", 10, [System.Drawing.FontStyle]::Bold)
    $label.Text = if ($global:savDir) { "Current: $(Split-Path $global:savDir -Leaf)" } else { "Please select your working directory" }
    $label.ForeColor = if ($global:savDir) { [System.Drawing.Color]::Green } else { [System.Drawing.Color]::Red }

    $btnSelt = New-Object System.Windows.Forms.Button
    $btnSelt.Text = "Browse Folders..."
    $btnSelt.Size = New-Object System.Drawing.Size(150, 35)
    $btnSelt.Location = New-Object System.Drawing.Point(145, 80)
    
    $btnSelt.Add_Click({
        $folderBrowser = New-Object System.Windows.Forms.FolderBrowserDialog
        if ($global:savDir) { $folderBrowser.SelectedPath = $global:savDir }
        
        # Ensure the browser dialog itself is also topmost
        if ($folderBrowser.ShowDialog((New-Object System.Windows.Forms.Form -Property @{TopMost = $true})) -eq [System.Windows.Forms.DialogResult]::OK) {
            $global:savDir = $folderBrowser.SelectedPath
            $configData['savDir'] = $global:savDir
            $configData | ConvertTo-Json | Set-Content -Path $configPath
            $sdform.Close()
        }
    })

    $sdform.Controls.AddRange(@($label, $btnSelt))
    
    # Final nudge to the front
    $sdform.Add_Shown({$sdform.Activate(); $sdform.BringToFront()})
    [void]$sdform.ShowDialog()
}
