function Set-WallpaperToRoot {
    param($SourceImage)
    
    # Use $FileDir if it exists, otherwise prompt user to select a folder
    $targetDir = $FileDir
    if (-not (Test-Path $targetDir -ErrorAction SilentlyContinue)) {
        [Windows.Forms.MessageBox]::Show("Root folder not set or does not exist. Please select folder to save background.", "Select Folder")
        $fb = New-Object System.Windows.Forms.FolderBrowserDialog
        if ($fb.ShowDialog() -eq "OK") { 
            $targetDir = $fb.SelectedPath 
        } else { 
            return 
        }
    }

    $destination = Join-Path $targetDir "bground.jpg"
    try {
        Copy-Item -Path $SourceImage -Destination $destination -Force
    } catch {
        [Windows.Forms.MessageBox]::Show("Failed to copy wallpaper: $($_.Exception.Message)", "Error")
    }
}
