function cxb_site_acc {
$Word = New-Object -ComObject Word.Application
   # Create Word application object
$Word = New-Object -ComObject Word.Application
$Word.Visible = $false  # Set to $true for debugging
Copy-Item -Path "$FileDir\.tmpl\site_access_req.docx" -Destination "$savDir\email draft-$cxb_name-site_access_req.docx"   
# Open document (use full path)
$Document = $Word.Documents.Open("$savDir\email draft-$cxb_name-site_access_req.docx" )

# Define replacements (use a hashtable for key-value pairs)
    $Replacements = @{
        "cxb_net_type" = $cxb_net_type
        "cxb_name" = $cxb_name
        "selcp" = $selcp
        "site_add" = $site_add
        "cxid_num" = $cxid_num
        "ccr_num" = $ccr_num
        "remedi_t" = $remedi_t
        "e_tk_num" = $e_tk_num
        }
    # Perform replacements
    foreach ($item in $Replacements.GetEnumerator()) {
        $FindText = $item.Key
        $ReplaceText = $item.Value
        $Document.Content.Find.Execute(
            $FindText,          # Find
            $false,             # MatchCase
            $true,              # MatchWholeWord
            $false,             # MatchWildcards
            $false,             # MatchSoundsLike
            $false,             # MatchAllWordForms
            $true,              # Forward
            1,                  # Wrap (wdFindContinue)
            $false,             # Format
            $ReplaceText,       # ReplaceWith
            2                   # Replace (wdReplaceAll)
        ) | Out-Null
    }

    # Save and close
    $Document.Save()
    $Document.Close()   
    }
