#...........................................Payload file integrity check.........................................
function file_int_chk {
                #-------------------------------------checks for and makes rtts.app sub folders
            foreach ($Folder in ".icons", ".html", ".tmpl") {
                $Destination = Join-Path -Path $FileDir -ChildPath $Folder
                if (!(Test-Path -Path $Destination)) {
                    New-Item -Path $Destination -ItemType Directory
                }
            }
            #------------------------------------- 
            #-------------------------------------Checks for all icons
            $Destination = "$FileDir\.icons\pc.png"    
            if (!(Test-Path -Path $Destination)) {
                payload_deploy_icons
                }
            #-------------------------------------
            $Destination = "$FileDir\.icons\web.png"    
            if (!(Test-Path -Path $Destination)) {
                payload_deploy_icons
                }
            #-------------------------------------
            $Destination = "$FileDir\.icons\logo.png"    
            if (!(Test-Path -Path $Destination)) {
                payload_deploy_icons
                }
            #-------------------------------------
            $Destination = "$FileDir\.icons\bground.jpg"    
            if (!(Test-Path -Path $Destination)) {
                payload_deploy_icons
                }
            #-------------------------------------
            $Destination = "$FileDir\.icons\call.png"    
            if (!(Test-Path -Path $Destination)) {
                payload_deploy_icons
                }
            #-------------------------------------
            $Destination = "$FileDir\.icons\rtts.app.run.png"    
            if (!(Test-Path -Path $Destination)) {
                payload_deploy_icons
                }
            #-------------------------------------
            $Destination = "$FileDir\.icons\sync.png"    
            if (!(Test-Path -Path $Destination)) {
                payload_deploy_icons
                }
            #-------------------------------------
            $Destination = "$FileDir\.icons\timer.png"    
            if (!(Test-Path -Path $Destination)) {
                payload_deploy_icons
                }
            #-------------------------------------
            $Destination = "$FileDir\.icons\wlog.png"    
            if (!(Test-Path -Path $Destination)) {
                payload_deploy_icons
                }
            #-------------------------------------
            #-------------------------------------check for all templates
            $Destination = "$FileDir\.tmpl\techlog_tmp.txt"    
            if (!(Test-Path -Path $Destination)) {
                payload_deploy_techlog
                }
            #-------------------------------------
            $Destination = "$savDir\clog.xlsx"
            if (!(Test-Path -Path $Destination)) {
                payload_deploy_clog
                }
            #--------------------------------
            $Destination = "$FileDir\.tmpl\dipatch_req.docx"
            if (!(Test-Path -Path $Destination)) {
                    payload_deploy_1
                    }
            #--------------------------------
            $Destination = "$FileDir\.tmpl\dispatch_up_req.docx"
