            $Destination = "$FileDir\.tmpl\nl2_utt_ucr_upd.docx"
            if (!(Test-Path -Path $Destination)) {
                    payload_deploy_3
                    }
            #--------------------------------
            $Destination = "$FileDir\.tmpl\type_II_out_adv.docx"
            if (!(Test-Path -Path $Destination)) {
                    payload_deploy_4
                    }
            #--------------------------------
