                    payload_deploy_5
                    }
            #--------------------------------
            $Destination = "$FileDir\.tmpl\tick_inv_num.docx"
            if (!(Test-Path -Path $Destination)) {
                    payload_deploy_6
                    }
            #--------------------------------
            $Destination = "$FileDir\.tmpl\site_access_req.docx"
            if (!(Test-Path -Path $Destination)) {
                    payload_deploy_7
                    }
            #--------------------------------
            $Destination = "$FileDir\.tmpl\major_out_adv.docx"
            if (!(Test-Path -Path $Destination)) {
                    payload_deploy_8
                    }
            #--------------------------------
            $Destination = "$FileDir\.tmpl\no_fault.docx"
            if (!(Test-Path -Path $Destination)) {
                    payload_deploy_9
                    }
