[void] [System.Reflection.Assembly]::LoadWithPartialName("System.Windows.Forms")
[void] [System.Reflection.Assembly]::LoadWithPartialName("System.Drawing")
#------------------------------launchHOME GUI string
$xaml = @"
<Window xmlns="http://schemas.microsoft.com/winfx/2006/xaml/presentation"
        xmlns:x="http://schemas.microsoft.com/winfx/2006/xaml"
        Title="||rtts.ja: App - Glass Morphism Edition"
        Width="800"
        Height="484"
        WindowStartupLocation="CenterScreen"
        WindowStyle="None"
        AllowsTransparency="True"
        Background="Transparent"
        Topmost="False"
        x:Name="MainWindow">

    <!-- Define Resources -->
    <Window.Resources>
        <!-- Gradient Brush for Background -->
        <LinearGradientBrush x:Key="GlassBackground" StartPoint="0,0" EndPoint="1,1">
            <GradientStop Color="#F5F5F5" Offset="0.0"/>
            <GradientStop Color="#EBEBEB" Offset="1.0"/>
        </LinearGradientBrush>
        <Style TargetType="GroupBox">
            <Setter Property="HeaderTemplate">
                <Setter.Value>
                    <DataTemplate>
                        <TextBlock Text="{Binding}" FontSize="16" FontWeight="Bold" Foreground="Red" />
                    </DataTemplate>
                </Setter.Value>
            </Setter>
            <Setter Property="Effect">
                <Setter.Value>
                    <DropShadowEffect Color="Gray" Direction="315" ShadowDepth="4" Opacity="0.5" />
                </Setter.Value>
            </Setter>
            <Setter Property="Margin" Value="8"/>
        </Style>
        <Style TargetType="Label">
            <Setter Property="FontWeight" Value="Bold"/>
        </Style>
    </Window.Resources>
    
    <Grid>
        <Grid.RowDefinitions>
            <RowDefinition Height="Auto"/>
            <RowDefinition Height="*"/>
        </Grid.RowDefinitions>

    <!-- Main Glass Container with Genie Effect Animation -->
    <Border Name="MainBorder"
            Grid.Row="0"
            Background="#F0F0F0"
            BorderBrush="#D0D0D0"
            BorderThickness="1"
            CornerRadius="15"
            Margin="10"
            Padding="20"
            Opacity="0.92"
            RenderTransformOrigin="0.5,0.5">
        <Border.RenderTransform>
            <ScaleTransform x:Name="BorderScale" ScaleX="1" ScaleY="1"/>
        </Border.RenderTransform>
        <Border.Effect>
            <DropShadowEffect
                Color="#000000"
                BlurRadius="30"
                ShadowDepth="8"
                Opacity="0.15"/>
        </Border.Effect>
        <Border.Triggers>
            <EventTrigger RoutedEvent="Border.Loaded">
                <BeginStoryboard>
                    <Storyboard>
                        <!-- Genie Effect: Scale from 0 to 1 -->
                        <DoubleAnimation
                            Storyboard.TargetName="BorderScale"
                            Storyboard.TargetProperty="ScaleX"
                            From="0.1" To="1" Duration="0:0:0.3">
                            <DoubleAnimation.EasingFunction>
                                <CubicEase EasingMode="EaseOut"/>
                            </DoubleAnimation.EasingFunction>
                        </DoubleAnimation>
                        <DoubleAnimation
                            Storyboard.TargetName="BorderScale"
                            Storyboard.TargetProperty="ScaleY"
                            From="0.1" To="1" Duration="0:0:0.6">
                            <DoubleAnimation.EasingFunction>
                                <CubicEase EasingMode="EaseOut"/>
                            </DoubleAnimation.EasingFunction>
                        </DoubleAnimation>
                    </Storyboard>
                </BeginStoryboard>
            </EventTrigger>
        </Border.Triggers>
        <DockPanel>
            <Menu DockPanel.Dock="Top" Background="#FFFFFF" Foreground="#000000" FontFamily="Segoe UI" FontSize="11">
                <MenuItem Header="Menu" FontWeight="Bold">
                    <MenuItem Header="Open Dir / File">
                        <MenuItem Header="Open File Explorer" Name="FileExplorerMenu"/>
                    </MenuItem>
                    <Separator/>
                    <MenuItem Header="App Info">
                        <MenuItem Header="About rtts app" Name="AboutMenu"/>
                        <MenuItem Header="Check for Update" Name="UpdateMenu"/>
                        <MenuItem Header="Uninstall rtts app" Name="UninstallMenu"/>
                    </MenuItem>
                    <Separator/>
                    <MenuItem Header="Reload App" Name="ReloadMenu"/>
                    <MenuItem Header="Exit" Name="ExitMenu"/>
                </MenuItem>
            </Menu>
            
            <StackPanel Orientation="Vertical" VerticalAlignment="Center" HorizontalAlignment="Center">
             <Grid Name="Title" Visibility="Visible" Margin="0">
                <!-- Titles -->
                <TextBlock Text="RTTS App 2026" FontSize="32" FontWeight="Bold" TextAlignment="Center" Foreground="#ee0a0a" />
                </Grid>
             <Grid Name="Title2" Visibility="Visible" Margin="1">
                <TextBlock Text="Call Logging and Email Creation Tool" FontSize="12" Foreground="#666666" TextAlignment="Center" Margin="0,10,0,0"/>
            </Grid>
            
                <!-- 2. CATEGORY ICONS PANEL (Shows when Log Call is clicked) -->
                <StackPanel Name="WebApp" Orientation="Vertical" HorizontalAlignment="Center" Visibility="Collapsed">
                    <StackPanel Orientation="Horizontal" HorizontalAlignment="Center">
                        <Border Name="LogSync" Width="225" Height="220" CornerRadius="12" Background="Transparent" Margin="10" Cursor="Hand" RenderTransformOrigin="0.5,0.5">
                            <Border.RenderTransform>
                                <ScaleTransform x:Name="BtnPCScale2" ScaleX="1" ScaleY="1"/>
                            </Border.RenderTransform>
                            <Border.Effect>
                                <DropShadowEffect Color="#33CFFF" BlurRadius="0" ShadowDepth="0" Opacity="0"/>
                            </Border.Effect>
                            <StackPanel VerticalAlignment="Center" HorizontalAlignment="Center">
                                <Image Source="$FileDir\.icons\sync.png" Width="160" Height="160" Margin="0,0,0,10"/>
                                <TextBlock Text="Sync Log" FontSize="18" FontWeight="Bold" Foreground="#333" TextAlignment="Center" HorizontalAlignment="Center"/>
                            </StackPanel>
                        </Border>
                        <Border Name="LWebApp" Width="225" Height="220" CornerRadius="12" Background="Transparent" Margin="10" Cursor="Hand" RenderTransformOrigin="0.5,0.5">
                            <Border.RenderTransform>
                                <ScaleTransform x:Name="BtnWebScale2" ScaleX="1" ScaleY="1"/>
                            </Border.RenderTransform>
                            <Border.Effect>
                                <DropShadowEffect Color="#7CBFFF" BlurRadius="0" ShadowDepth="0" Opacity="0"/>
                            </Border.Effect>
                            <StackPanel VerticalAlignment="Center" HorizontalAlignment="Center">
                                <Image Source="$FileDir\.icons\wlog.png" Width="160" Height="160" Margin="0,0,0,10"/>
                                <TextBlock Text="Launch web-CLST" FontSize="18" FontWeight="Bold" Foreground="#333" TextAlignment="Center" HorizontalAlignment="Center"/>
                            </StackPanel>
                        </Border>
                    </StackPanel>
                    <StackPanel Name="WallpaperPanel" Orientation="Vertical" HorizontalAlignment="Center" Visibility="Visible" Margin="0,10,0,00">
                        <GroupBox Header="Wallpaper" BorderBrush="Red" BorderThickness="1" Padding="8" Width="240" Background="#FFFFFF">
                            <StackPanel>
                                <CheckBox Name="chkWallpaper" Content="Change Clog Wallpaper"/>
                            </StackPanel>
                        </GroupBox>
                    </StackPanel>
                </StackPanel>
                <StackPanel Name="CLST" Orientation="Horizontal" HorizontalAlignment="Center" Visibility="Collapsed">
                    <Border Name="BtnPC" Width="225" Height="220" CornerRadius="12" Background="Transparent" Margin="10" Cursor="Hand" RenderTransformOrigin="0.5,0.5">
                        <Border.RenderTransform>
                            <ScaleTransform x:Name="BtnPCScale" ScaleX="1" ScaleY="1"/>
                        </Border.RenderTransform>
                        <Border.Effect>
                            <DropShadowEffect Color="#33CFFF" BlurRadius="0" ShadowDepth="0" Opacity="0"/>
                        </Border.Effect>
                        <StackPanel VerticalAlignment="Center">
                            <Image Source="$FileDir\.icons\pc.png" Width="160" Height="160" Margin="0,0,0,0"/>                            <TextBlock Text="PC App" FontSize="18" FontWeight="Bold" Foreground="#333" TextAlignment="Center"/>
                        </StackPanel>
                    </Border>
                    <Border Name="BtnWeb" Width="225" Height="220" CornerRadius="12" Background="Transparent" Margin="10" Cursor="Hand" RenderTransformOrigin="0.5,0.5">
                        <Border.RenderTransform>
                            <ScaleTransform x:Name="BtnWebScale" ScaleX="1" ScaleY="1"/>
                        </Border.RenderTransform>
                        <Border.Effect>
                            <DropShadowEffect Color="#7CBFFF" BlurRadius="0" ShadowDepth="0" Opacity="0"/>
                        </Border.Effect>
                        <StackPanel VerticalAlignment="Center">
                            <Image Source="$FileDir\.icons\web.png" Width="160" Height="160" Margin="0,0,0,0"/>
                            <TextBlock Text="Web Portal" FontSize="18" FontWeight="Bold" Foreground="#333" TextAlignment="Center"/>
                        </StackPanel>
                    </Border>
                </StackPanel>
                <!-- 1. MAIN BUTTONS CONTAINER (Hides when Log Call is clicked) -->
                <StackPanel Name="MainButtonsPanel" Orientation="Horizontal" HorizontalAlignment="Center" Visibility="Visible" Margin="0,30,0,0">
                    <!-- Btn1: Log Call -->
                    <Border Name="Btn1" Width="195" Height="120" CornerRadius="12" Background="#1eb6e0" Margin="10" Cursor="Hand" RenderTransformOrigin="0.5,0.5">
                        <Border.RenderTransform>
                            <ScaleTransform x:Name="Btn1Scale" ScaleX="1" ScaleY="1"/>
                        </Border.RenderTransform>
                        <StackPanel VerticalAlignment="Center"><TextBlock Text="📋" FontSize="36" Foreground="White" TextAlignment="Center"/><TextBlock Text="Log Call" FontWeight="Bold" Foreground="White" TextAlignment="Center"/></StackPanel>
                    </Border>
                    <!-- Btn2: Create Email -->
                    <Border Name="Btn2" Width="225" Height="120" CornerRadius="12" Background="#F0A500" Margin="10" Cursor="Hand" RenderTransformOrigin="0.5,0.5">
                        <Border.RenderTransform>
                            <ScaleTransform x:Name="Btn2Scale" ScaleX="1" ScaleY="1"/>
                        </Border.RenderTransform>
                        <StackPanel VerticalAlignment="Center"><TextBlock Text="✉️" FontSize="36" Foreground="White" TextAlignment="Center"/><TextBlock Text="Create Email" FontWeight="Bold" Foreground="White" TextAlignment="Center"/></StackPanel>
                    </Border>
                    <!-- Btn3: Start Timer -->
                    <Border Name="Btn3" Width="225" Height="120" CornerRadius="12" Background="#34A853" Margin="10" Cursor="Hand" RenderTransformOrigin="0.5,0.5">
                        <Border.RenderTransform>
                            <ScaleTransform x:Name="Btn3Scale" ScaleX="1" ScaleY="1"/>
                        </Border.RenderTransform>
                        <StackPanel VerticalAlignment="Center"><TextBlock Text="⏱️" FontSize="36" Foreground="White" TextAlignment="Center"/><TextBlock Text="Start Timer" FontWeight="Bold" Foreground="White" TextAlignment="Center"/></StackPanel>
                    </Border>
                </StackPanel>
                <!-- Info Section -->
                <Border Background="#F0F4FF" CornerRadius="10" Padding="15" Margin="0,30,0,0" Width="600">
                    <StackPanel>
                        <TextBlock Text="rtts App v3.0 - Win 11 Edition" TextAlignment="Center" FontSize="12" FontWeight="Bold" Foreground="#0078D4"/>
                        <TextBlock Text="Modern WPF design with acrylic blur effects and smooth animations" TextAlignment="Center" FontSize="11" Foreground="#666666"/>
                    </StackPanel>
                </Border>

            </StackPanel>
        </DockPanel>
    </Border>
</Grid>
</Window>
"@

# ===== CREATE AND SHOW WPF WINDOW =====
function launchHOME  {
    AppPersist                      #-------check for File paths and runtime for app 
    file_int_chk                #-------file integrith checks

    [System.Windows.Forms.MessageBox]::Show($disclaimertext)
    $window = New-Object System.Windows.Forms.Form
    $window.TopMost = $true


    # Parse XAML
    $reader = New-Object System.Xml.XmlNodeReader([xml]$xaml)
    $window = [Windows.Markup.XamlReader]::Load($reader)

    $btn1 = $window.FindName("Btn1")
    $btn2 = $window.FindName("Btn2")
    $btn3 = $window.FindName("Btn3")
    $BtnPC = $window.FindName("BtnPC")
    $BtnWeb = $window.FindName("BtnWeb")
    $mainWindow = $window.FindName("MainWindow")
    $clst = $window.FindName("CLST")
    $lwebapp = $window.FindName("LWebApp")
    $logsync = $window.FindName("LogSync")
    $webapp = $window.FindName("WebApp")
    $chkWallpaper = $window.FindName("chkWallpaper")
    #---------------------
    # Get menu items
    $menuFileExplorer = $window.FindName("FileExplorerMenu")
    $menuAbout = $window.FindName("AboutMenu")
    $menuUpdate = $window.FindName("UpdateMenu")
    $menuUninstall = $window.FindName("UninstallMenu")
    $menuReload = $window.FindName("ReloadMenu")
    $menuExit = $window.FindName("ExitMenu")
    
    # ===== MENU CLICK HANDLERS =====
    if ($menuFileExplorer) {
        $menuFileExplorer.Add_Click({
            [System.Windows.MessageBox]::Show("Opening Ticket Log Folder/ Working Directory", "Info", [System.Windows.MessageBoxButton]::OK, [System.Windows.MessageBoxImage]::Information) | Out-Null
        explorer /select, $savDir
        })
    }
    
    if ($menuAbout) {
        $menuAbout.Add_Click({
            [System.Windows.MessageBox]::Show($aboutText, "About RTTS App", [System.Windows.MessageBoxButton]::OK, [System.Windows.MessageBoxImage]::Information) | Out-Null
        })
    }
    
    if ($menuUpdate) {
        $menuUpdate.Add_Click({
            [System.Windows.MessageBox]::Show("Checking for updates...`nVisiting GitHub repository", "Update Check", [System.Windows.MessageBoxButton]::OK, [System.Windows.MessageBoxImage]::Information) | Out-Null
            Start-Process "https://github.com/rttsja/rtts-apps.git"
        })
    }
    
    if ($menuUninstall) {
        $menuUninstall.Add_Click({
            $result = [System.Windows.MessageBox]::Show("Are you sure you want to uninstall RTTS App?", "Confirm Uninstall", [System.Windows.MessageBoxButton]::YesNo, [System.Windows.MessageBoxImage]::Question)
            if ($result -eq "Yes") {
                $window.Close()
                uninstall_rtts}
        })
    }
    
    if ($menuReload) {
        $menuReload.Add_Click({
            $window.Close()
           launchHOME 
        })
    }
    
    if ($menuExit) {
        $menuExit.Add_Click({
            $window.Close()
        })
    }
 # ===== HOVER EFFECTS WITH SIZE AND GLOW =====
    @($btn1, $btn2, $btn3) | ForEach-Object {
        $btn = $_
        
        $btn.Add_MouseEnter({
            # Get the scale transform names dynamically
            $btn_name = $this.Name
            $scale_obj = $this.FindName($btn_name + "Scale")
            
            if ($scale_obj) {
                # Animate to larger size
                $scaleX_anim = New-Object System.Windows.Media.Animation.DoubleAnimation
                $scaleX_anim.To = 1.20
                $scaleX_anim.Duration = New-Object System.Windows.Duration([System.TimeSpan]::FromMilliseconds(200))
                
                $scaleY_anim = New-Object System.Windows.Media.Animation.DoubleAnimation
                $scaleY_anim.To = 1.20
                $scaleY_anim.Duration = New-Object System.Windows.Duration([System.TimeSpan]::FromMilliseconds(200))
                
                $scale_obj.BeginAnimation([System.Windows.Media.ScaleTransform]::ScaleXProperty, $scaleX_anim)
                $scale_obj.BeginAnimation([System.Windows.Media.ScaleTransform]::ScaleYProperty, $scaleY_anim)
            }
            
            # Enhanced glow - reduce opacity slightly for glass effect
            $this.Opacity = 0.88
        })
        
        $btn.Add_MouseLeave({
            # Get the scale transform names dynamically
            $btn_name = $this.Name
            $scale_obj = $this.FindName($btn_name + "Scale")
            
            if ($scale_obj) {
                # Animate back to normal size
                $scaleX_anim = New-Object System.Windows.Media.Animation.DoubleAnimation
                $scaleX_anim.To = 1.0
                $scaleX_anim.Duration = New-Object System.Windows.Duration([System.TimeSpan]::FromMilliseconds(200))
                
                $scaleY_anim = New-Object System.Windows.Media.Animation.DoubleAnimation
                $scaleY_anim.To = 1.0
                $scaleY_anim.Duration = New-Object System.Windows.Duration([System.TimeSpan]::FromMilliseconds(200))
                
                $scale_obj.BeginAnimation([System.Windows.Media.ScaleTransform]::ScaleXProperty, $scaleX_anim)
                $scale_obj.BeginAnimation([System.Windows.Media.ScaleTransform]::ScaleYProperty, $scaleY_anim)
            }
            
            # Restore full opacity
            $this.Opacity = 1.0
        })
    }
    # ===== PC / Web Hover Effects =====
    @($BtnPC, $BtnWeb, $logsync, $lwebapp) | ForEach-Object {
        $btn = $_
        if ($btn) {
            $btn.Add_MouseEnter({
                $scale = $this.RenderTransform
                if ($scale -is [System.Windows.Media.ScaleTransform]) {
                    $scaleX = New-Object System.Windows.Media.Animation.DoubleAnimation
                    $scaleX.To = 1.35
                    $scaleX.Duration = New-Object System.Windows.Duration([System.TimeSpan]::FromMilliseconds(220))
                    $ease = New-Object System.Windows.Media.Animation.BounceEase
                    $ease.Bounces = 2
                    $ease.Bounciness = 2
                    $ease.EasingMode = [System.Windows.Media.Animation.EasingMode]::EaseOut
                    $scaleX.EasingFunction = $ease

                    $scaleY = New-Object System.Windows.Media.Animation.DoubleAnimation
                    $scaleY.To = 1.35
                    $scaleY.Duration = $scaleX.Duration
                    $scaleY.EasingFunction = $ease

                    $scale.BeginAnimation([System.Windows.Media.ScaleTransform]::ScaleXProperty, $scaleX)
                    $scale.BeginAnimation([System.Windows.Media.ScaleTransform]::ScaleYProperty, $scaleY)
                }
                $effect = $this.Effect
                if ($effect -is [System.Windows.Media.Effects.DropShadowEffect]) {
                    $effect.BlurRadius = 24
                    $effect.Opacity = 0.65
                }
            })

            $btn.Add_MouseLeave({
                $scale = $this.RenderTransform
                if ($scale -is [System.Windows.Media.ScaleTransform]) {
                    $scaleX = New-Object System.Windows.Media.Animation.DoubleAnimation
                    $scaleX.To = 1.0
                    $scaleX.Duration = New-Object System.Windows.Duration([System.TimeSpan]::FromMilliseconds(180))

                    $scaleY = New-Object System.Windows.Media.Animation.DoubleAnimation
                    $scaleY.To = 1.0
                    $scaleY.Duration = $scaleX.Duration

                    $scale.BeginAnimation([System.Windows.Media.ScaleTransform]::ScaleXProperty, $scaleX)
                    $scale.BeginAnimation([System.Windows.Media.ScaleTransform]::ScaleYProperty, $scaleY)
                }
                $effect = $this.Effect
                if ($effect -is [System.Windows.Media.Effects.DropShadowEffect]) {
                    $effect.BlurRadius = 0
                    $effect.Opacity = 0
                }
            })
        }
    }
    
    # ===== BUTTON CLICK EVENTS =====
    

    $btn1.Add_MouseDown({ #Call Log Launcher (PC & WEB)
        $btn1.Visibility = [System.Windows.Visibility]::Hidden
        $btn2.Visibility = [System.Windows.Visibility]::Hidden
        $btn3.Visibility = [System.Windows.Visibility]::Hidden
        $clst.Visibility = [System.Windows.Visibility]::Visible    
    })
    
    $btn2.Add_MouseDown({ #---Email Creation Placeholder---
                        $window.Close()
                        genEMAIL    
                        })
    
    $btn3.Add_MouseDown({ #---Timer App Launch---
                    $window.Close()
                     `   timer_app
                        })
    $BtnPC.Add_MouseDown({ #PC Call Log Launcher
        # Launch PC call log form and close the selection panels.
        $window.Close()
        call_log_form
    })

    $BtnWeb.Add_MouseDown({ #Web Call Log Launcher
        $clst.Visibility = [System.Windows.Visibility]::Hidden
        $webapp.Visibility = [System.Windows.Visibility]::Visible
    })

   $logsync.Add_MouseDown({
        [Windows.Forms.MessageBox]::Show("Choose clog file for synchronization.", "Selection Required")
    $excelDialog = New-Object System.Windows.Forms.OpenFileDialog
    $excelDialog.Title = "Select Excel File"
    $excelDialog.Filter = "Excel Files (*.xlsx)|*.xlsx"
    if ($excelDialog.ShowDialog() -eq "OK") {
        sync_clog -path $excelDialog.FileName
        $csvPath = "$env:USERPROFILE\Downloads\call_log.csv"
        if (Test-Path $csvPath) { Remove-Item $csvPath -Force }
        [Windows.Forms.MessageBox]::Show("Process Finished.", "clog now Synched")
    }
    })
   $lwebapp.Add_MouseDown({
        $window.Close()
        if ($chkWallpaper -and $chkWallpaper.IsChecked -eq $true) {
            [Windows.Forms.MessageBox]::Show("Please select the image file you wish to use as your wallpaper.", "Step 1: Select Image")
            $fb = New-Object System.Windows.Forms.OpenFileDialog
            $fb.Title = "Select Wallpaper Image"
            $fb.Filter = "Image Files (*.jpg;*.jpeg;*.png)|*.jpg;*.jpeg;*.png"
            if ($fb.ShowDialog() -eq "OK") {
                Set-WallpaperToRoot -SourceImage $fb.FileName
            }
            
        }

    # First, try to find index.html in the selected $FileDir
    $targetHtml = Join-Path $FileDir/.html/ "index.html"

    if (Test-Path $targetHtml) {
        Start-Process $targetHtml
    } else {
        [Windows.Forms.MessageBox]::Show("index.html not found in root. Searching Downloads...", "File Not Found")
        
        $searchPattern = "$env:USERPROFILE\Downloads\*\rtts.app\.html\index.html"
        $foundFile = Get-Item $searchPattern -ErrorAction SilentlyContinue | Select-Object -First 1

        if ($foundFile) {
            Start-Process $foundFile.FullName
        } else {
            [Windows.Forms.MessageBox]::Show("Could not find index.html automatically. Please locate manually.", "Manual Selection")
            $htmlDialog = New-Object System.Windows.Forms.OpenFileDialog
            $htmlDialog.Title = "Locate index.html"
            $htmlDialog.Filter = "HTML Files (*.html)|*.html"
            if ($htmlDialog.ShowDialog() -eq "OK") { Start-Process $htmlDialog.FileName }
        }
    }
    })

    # ===== WINDOW DRAG SUPPORT =====
    $mainWindow.Add_MouseLeftButtonDown({
        $mainWindow.DragMove()
    })
    
    # Show window
    $mainWindow.ShowDialog() | Out-Null
}
#...............................
function call_log_form {
    Add-Type -AssemblyName PresentationFramework, PresentationCore, WindowsBase, System.Xaml, System.Windows.Forms

    $topMostForm = New-Object System.Windows.Forms.Form
    $topMostForm.TopMost = $true

    [xml]$xaml = @"
    <Window xmlns="http://schemas.microsoft.com/winfx/2006/xaml/presentation"
        xmlns:x="http://schemas.microsoft.com/winfx/2006/xaml"
        Title="||rtts.ja Desktop Call Log" Height="850" Width="750" 
        WindowStartupLocation="CenterScreen"
        Background="#F5F5F5">
    
    <Window.Resources>
       <Style TargetType="GroupBox">
            <Setter Property="HeaderTemplate">
                <Setter.Value>
                    <DataTemplate>
                        <TextBlock Text="{Binding}" FontSize="16" FontWeight="Bold" Foreground="Red" />
                    </DataTemplate>
                </Setter.Value>
            </Setter>
            <Setter Property="Effect">
                <Setter.Value>
                    <DropShadowEffect Color="Gray" Direction="315" ShadowDepth="4" Opacity="0.5" />
                </Setter.Value>
            </Setter>
            <Setter Property="Margin" Value="8"/>
        </Style>
        <Style TargetType="Label">
            <Setter Property="FontWeight" Value="Bold"/>
        </Style>
    </Window.Resources>

    <Grid Margin="10">
        <Grid.RowDefinitions>
            <RowDefinition Height="Auto"/> 
            <RowDefinition Height="Auto"/> 
            <RowDefinition Height="Auto"/> 
            <RowDefinition Height="*"/>    
            <RowDefinition Height="Auto"/> 
        </Grid.RowDefinitions>
        <Grid.ColumnDefinitions>
            <ColumnDefinition Width="*"/>
            <ColumnDefinition Width="*"/>
        </Grid.ColumnDefinitions>
        <!-- Menu -->
        <Menu DockPanel.Dock="Top" Background="#FFFFFF" Foreground="#000000" FontFamily="Segoe UI" FontSize="11">
                <MenuItem Header="Menu" FontWeight="Bold">
                    <MenuItem Header="Open Dir / File">
                        <MenuItem Header="Open File Explorer" Name="FileExplorerMenu"/>
                    </MenuItem>
                    <Separator/>
                    <MenuItem Header="App Info">
                        <MenuItem Header="About rtts app" Name="AboutMenu"/>
                        <MenuItem Header="Check for Update" Name="UpdateMenu"/>
                        <MenuItem Header="Uninstall rtts app" Name="UninstallMenu"/>
                    </MenuItem>
                    <Separator/>
                    <MenuItem Header="Reload App" Name="ReloadMenu"/>
                    <MenuItem Header="Exit" Name="ExitMenu"/>
                </MenuItem>
            </Menu>
        <!-- NEW TITLE SECTION -->
        <TextBlock Text="Call Log Form" 
                   Grid.Row="0" Grid.ColumnSpan="2" 
                   HorizontalAlignment="Center" 
                   FontSize="38" FontWeight="Bold" Foreground="Red" 
                   Margin="0,10,0,20">
            <TextBlock.Effect>
                <DropShadowEffect Color="Gray" Direction="315" ShadowDepth="4" Opacity="0.5" />
            </TextBlock.Effect>
        </TextBlock>

        <GroupBox Header="Caller Info" Grid.Row="1" Grid.Column="0" Padding="10" Background="#f0f3c3">
            <StackPanel>
                <Label Content="Caller Name:"/>
                <TextBox Name="cxn" Margin="0,2"/>
                <Label Content="Caller Number:"/>
                <TextBox Name="cx_ph" Margin="0,2"/>
                <Label Content="Caller Email:"/>
                <TextBox Name="cx_email" Margin="0,2"/>
            </StackPanel>
        </GroupBox>

        <GroupBox Header="Customer Information" Grid.Row="1" Grid.Column="1" Padding="10" Background="#81b0b6">
            <StackPanel>
                <Label Content="Customer Name:"/>
                <TextBox Name="cxb_name"  Margin="0,2"/>
                <Label Content="Customer CID Number:"/>
                <TextBox Name="cxid_num"  Margin="0,2"/>
                <Label Content="Customer Location:"/>
                <TextBox Name="site_add"  Margin="0,2"/>
            </StackPanel>
        </GroupBox>

        <GroupBox Header="Call Details" Grid.Row="2" Grid.ColumnSpan="2" Padding="10" Background="#a7f7a7">
            <Grid>
                <Grid.ColumnDefinitions>
                    <ColumnDefinition Width="1.2*"/>
                    <ColumnDefinition Width="*"/>
                </Grid.ColumnDefinitions>

                <StackPanel Grid.Column="0" Margin="5,0">
                    <Label Content="Service Type:"/>
                    <ComboBox Name="serviceType" Margin="0,0,0,5">
                        <ComboBoxItem Content="Ticket Update || UCR Update" />
                        <ComboBoxItem Content="PTP-Commercial Internet" />
                        <ComboBoxItem Content="Dark Fiber" />
                        <ComboBoxItem Content="DNS" />
                        <ComboBoxItem Content="DS3" />
                        <ComboBoxItem Content="Ethernet / DIA" />
                        <ComboBoxItem Content="FTTT" />
                        <ComboBoxItem Content="Monitor / Surveillance" />
                        <ComboBoxItem Content="OC12" />
                        <ComboBoxItem Content="OC192" />
                        <ComboBoxItem Content="OC3" />
                        <ComboBoxItem Content="OC48" />
                        <ComboBoxItem Content="Optical Transport Service" />
                        <ComboBoxItem Content="Turn-Up" />
                        <ComboBoxItem Content="VOIP" />
                        <ComboBoxItem Content="Wave" />
                    </ComboBox>

                    <Label Content="Issue Type:"/>
                    <ComboBox Name="issueType" Margin="0,0,0,10">
                        <ComboBoxItem Content="[OOS]-HARD DOWN" />
                        <ComboBoxItem Content="[LOR]-Redundancy" />
                        <ComboBoxItem Content="LINK FLAP" />
                        <ComboBoxItem Content="FRAME LOSS" />
                        <ComboBoxItem Content="Technical Support" />
                        <ComboBoxItem Content="Request" />
                    </ComboBox>

                    <UniformGrid Columns="2">
                        <StackPanel Margin="0,0,5,0">
                            <Label Content="Date:"/>
                            <DatePicker Name="ticket_date" />
                        </StackPanel>
                        <StackPanel Margin="5,0,0,0">
                            <Label Content="Time:"/>
                            <TextBox Name="ticket_time" Height="24" VerticalContentAlignment="Center"/>
                        </StackPanel>
                    </UniformGrid>
                </StackPanel>
                <StackPanel Name= "rttslogo" Grid.Column ="3">
                        <Image Source="$FileDir\.icons\logo.png" Width="220" Height="190" Margin="60,0,0,0"/>
                </StackPanel>
                <StackPanel Grid.Column="1" Margin="15,0,5,0">
                    <Label Content="Ticket Created?"/>
                    <StackPanel Orientation="Horizontal" Margin="0,0,0,5">
                        <RadioButton Name="RadYes" Content="Yes" Margin="0,0,15,0" />
                        <RadioButton Name="RadNo" Content="No" IsChecked="True" Margin="0,0,15,0" />
                    </StackPanel>
                    <StackPanel Name="TicketPanel">
                        <Label Content="External Ticket #:"/>
                        <TextBox Name="ext_ticket" Margin="0,0,0,5"/>
                        <Label Content="Internal Ticket #:"/>
                        <TextBox Name="int_ticket" Margin="0,0,0,5"/>
                    </StackPanel>
                    
                </StackPanel>
            </Grid>
        </GroupBox>

        <GroupBox Header="Notes" Grid.Row="3" Grid.ColumnSpan="2" Padding="10" Background="#e8e8e8">
            <TextBox Name="notes" AcceptsReturn="True" TextWrapping="Wrap" VerticalScrollBarVisibility="Auto" MinHeight="100"/>
        </GroupBox>
                <!-- OPTIONS (Left side of Row 4) -->
        <StackPanel Name="Options" Grid.Row="4" Grid.Column="0" VerticalAlignment="Center" Margin="10,0">
            <CheckBox Name="chkTimer" Content="Start Timer" Margin="0,2" FontWeight="Bold"/>
            <CheckBox Name="chkEmail" Content="Create Email" Margin="0,2" FontWeight="Bold"/>
        </StackPanel>

        <!-- FOOTER BUTTONS (Right side of Row 4) -->
        <StackPanel Grid.Row="4" Grid.Column="1" Orientation="Horizontal" HorizontalAlignment="Right" VerticalAlignment="Center" Margin="0,10,10,10">
            <Button Name="btnClear" Content="Clear Form" Width="100" Height="30" Margin="5"/>
            <Button Name="btnSubmit" Content="Log Call" Width="120" Height="45" Background="#0683ff" Foreground="White" FontWeight="Bold" Margin="5"/>
        </StackPanel>

        </Grid>
    </Window>
"@
# --- 1. Load UI and Map Controls ---
$reader = New-Object System.Xml.XmlNodeReader $xaml
$cform = [Windows.Markup.XamlReader]::Load($reader)

# --- 2. Find UI Elements (Mapped to $c object for consistency) ---
$menuFileExplorer = $cform.FindName("FileExplorerMenu")
$menuAbout        = $cform.FindName("AboutMenu")
$menuUpdate       = $cform.FindName("UpdateMenu")
$menuUninstall    = $cform.FindName("UninstallMenu")
$menuReload       = $cform.FindName("ReloadMenu")
$menuExit         = $cform.FindName("ExitMenu")

 # ===== MENU CLICK HANDLERS =====
    if ($menuFileExplorer) {
        $menuFileExplorer.Add_Click({
            [System.Windows.MessageBox]::Show("Opening Ticket Log Folder/ Working Directory", "Info", [System.Windows.MessageBoxButton]::OK, [System.Windows.MessageBoxImage]::Information) | Out-Null
        explorer /select, $savDir
        })
    }
    
    if ($menuAbout) {
        $menuAbout.Add_Click({
            [System.Windows.MessageBox]::Show($aboutText, "About RTTS App", [System.Windows.MessageBoxButton]::OK, [System.Windows.MessageBoxImage]::Information) | Out-Null
        })
    }
    
    if ($menuUpdate) {
        $menuUpdate.Add_Click({
            [System.Windows.MessageBox]::Show("Checking for updates...`nVisiting GitHub repository", "Update Check", [System.Windows.MessageBoxButton]::OK, [System.Windows.MessageBoxImage]::Information) | Out-Null
            Start-Process "https://github.com/rttsja/rtts-apps.git"
        })
    }
    
    if ($menuUninstall) {
        $menuUninstall.Add_Click({
            $result = [System.Windows.MessageBox]::Show("Are you sure you want to uninstall RTTS App?", "Confirm Uninstall", [System.Windows.MessageBoxButton]::YesNo, [System.Windows.MessageBoxImage]::Question)
            if ($result -eq "Yes") {
                $cform.Close()
                uninstall_rtts}
        })
    }
    
    if ($menuReload) {
        $menuReload.Add_Click({
               $cform.DialogResult = [System.Windows.Forms.DialogResult]::OK
                $cform.Close()
                $cform.ShowDialog()
                $cform.Dispose()
                reload_form})
        }    
    if ($menuExit) {
        $menuExit.Add_Click({
            $window.Close()
        })
    }

$c = [PSCustomObject]@{
    cxn         = $cform.FindName("cxn")
    ccr_num     = $cform.FindName("int_ticket")
    e_tk_num    = $cform.FindName("ext_ticket")
    cx_ph       = $cform.FindName("cx_ph")
    cx_email    = $cform.FindName("cx_email")
    cxb_name    = $cform.FindName("cxb_name")
    cxid_num    = $cform.FindName("cxid_num")
    site_add    = $cform.FindName("site_add")
    sum_x       = $cform.FindName("sum_x")
    selcp       = $cform.FindName("issueType")
    servtyp     = $cform.FindName("serviceType")
    ticket_date = $cform.FindName("ticket_date")
    ticket_time = $cform.FindName("ticket_time")
    chkTimer    = $cform.FindName("chkTimer")
    chkEmail    = $cform.FindName("chkEmail")
    btnSubmit   = $cform.FindName("btnSubmit")
    btnClear    = $cform.FindName("btnClear")
    notes       = $cform.FindName("notes")
    TicketPanel = $cform.FindName("TicketPanel")
    RadNo       = $cform.FindName("RadNo")
    RadYes      = $cform.FindName("RadYes")
    rttslogo    = $cform.FindName("rttslogo")
}

# --- 3. Initialize Defaults ---
if ($c.ticket_date) { $c.ticket_date.SelectedDate = Get-Date }
if ($c.ticket_time) { $c.ticket_time.Text = Get-Date -Format "hh:mm tt" }
if ($c.TicketPanel) { $c.TicketPanel.Visibility = "Hidden" }

# --- 4. Menu Click Handlers ---
if ($menuFileExplorer) { $menuFileExplorer.Add_Click({ explorer /select, $FileDir }) }
if ($menuAbout)        { $menuAbout.Add_Click({ [Windows.MessageBox]::Show($aboutText, "About") }) }
if ($menuUpdate)       { $menuUpdate.Add_Click({ Open-update }) }
if ($menuExit)         { $menuExit.Add_Click({ $cform.Close() }) }

# --- 5. Logic Handlers ---

# Toggle Panel Visibility
$c.RadNo.Add_Checked({ 
    $c.TicketPanel.Visibility = "Collapsed" 
    $c.rttslogo.Visibility = "Visible"
})
$c.RadYes.Add_Checked({ 
    $c.TicketPanel.Visibility = "Visible" 
    $c.rttslogo.Visibility = "Collapsed"
})

# Clear Button Function
$c.btnClear.Add_Click({
    @($c.cxn, $c.ccr_num, $c.e_tk_num, $c.cx_ph, $c.cx_email, $c.cxb_name, $c.cxid_num, $c.site_add, $c.sum_x, $c.notes) | ForEach-Object { if ($_) { $_.Clear() } }
    if ($c.servtyp -is [System.Windows.Controls.ComboBox]) { $c.servtyp.SelectedIndex = -1 }
    if ($c.selcp -is [System.Windows.Controls.ComboBox])   { $c.selcp.SelectedIndex = -1 }
    $c.chkTimer.IsChecked = $false
    $c.chkEmail.IsChecked = $false
})

# Submit Button Function
$c.btnSubmit.Add_Click({
    # Capture values using .Text from the $c object
    $global:cxn      = $c.cxn.Text
    $global:ccr_num  = $c.ccr_num.Text
    $global:e_tk_num = $c.e_tk_num.Text
    $global:cx_ph    = $c.cx_ph.Text
    $global:cx_email = $c.cx_email.Text
    $global:site_add = $c.site_add.Text
    $global:sum_x    = $c.sum_x.Text
    $global:servtyp  = $c.servtyp.Text
    $global:selcp    = $c.selcp.Text
    $global:sum_x    = $c.notes.Text
    $global:sum_x    = $c.notes.Text
    $global:outtime    = $c.ticket_time.Text
    $global:outdate    = $c.ticket_date.Text

    # Sanitize inputs for file naming
    $global:cxb_name = $c.cxb_name.Text -replace '[\\\/:*?"<>|]', ''
    $global:cxid_num = $c.cxid_num.Text -replace '[\\\/:*?"<>|]', '' 

    $Summary = @"
Customer Name: $global:cxn
Phone:         $global:cx_ph
Email:         $global:cx_email
------------------------------
CCR Number:    $global:ccr_num
Ticket Number: $global:e_tk_num
------------------------------
Billing Name:  $global:cxb_name
CID Number:    $global:cxid_num
Site Address:  $global:site_add
------------------------------
Service Type:  $global:servtyp
Outage Start Date: $global:outdate
Outage Start Time:  $global:outtime
------------------------------
Issue Reported:   $global:selcp    
Notes:         $global:sum_x
"@ 
    
    [System.Windows.MessageBox]::Show($Summary, "Form Results")

    # Screenshot and Logging
    $bounds = [Drawing.Rectangle]::FromLTRB(0, 0, 1800, 1100)
    screenshot $bounds "$savDir\clog-$($global:cxb_name)-$($global:cxid_num)-$timeS.jpg"
    
    create_techlog
    create_clog

    $cform.Close()
    
    # Open Results
    Invoke-Item "$savDir\tech-$($global:cxb_name)-*.txt"
    Invoke-Item "$savDir\clog.xlsx"

    if ($c.chkTimer.IsChecked) { timer_app }
    if ($c.chkEmail.IsChecked) { genEMAIL }
})

# --- 6. Launch the Form ---
$cform.ShowDialog() | Out-Null
}

#------------------------------
#------------------genEMAIL FORM
function genEMAIL {
    # 1. Load Required Assemblies
    Add-Type -AssemblyName PresentationFramework, PresentationCore, WindowsBase, System.Xaml

    $topMostForm = New-Object System.Windows.Forms.Form
    $topMostForm.TopMost = $true

    # 2. Define XAML
    [xml]$xaml = @"
    <Window xmlns="http://schemas.microsoft.com/winfx/2006/xaml/presentation"
            xmlns:x="http://schemas.microsoft.com/winfx/2006/xaml"
            Title="||rtts.ja Email Generator" Height="470" Width="1250" 
            WindowStartupLocation="CenterScreen"
            Background="#F5F5F5">

        <Window.Resources>
           <Style TargetType="GroupBox">
                <Setter Property="HeaderTemplate">
                    <Setter.Value>
                        <DataTemplate>
                            <TextBlock Text="{Binding}" FontSize="16" FontWeight="Bold" Foreground="Red" />
                        </DataTemplate>
                    </Setter.Value>
                </Setter>
                <Setter Property="Effect">
                    <Setter.Value>
                        <DropShadowEffect Color="Gray" Direction="315" ShadowDepth="4" Opacity="0.5" />
                    </Setter.Value>
                </Setter>
                <Setter Property="Margin" Value="8"/>
                <Setter Property="VerticalAlignment" Value="Top"/>
            </Style>
            <Style TargetType="Label">
                <Setter Property="FontWeight" Value="Bold"/>
            </Style>
        </Window.Resources>

        <Grid Margin="10">
            <Grid.RowDefinitions>
                <RowDefinition Height="Auto"/> <!-- Menu -->
                <RowDefinition Height="Auto"/> <!-- Header -->
                <RowDefinition Height="*"/>    <!-- Content Row -->
            </Grid.RowDefinitions>
            <Grid.ColumnDefinitions>
                <ColumnDefinition Width="*"/> <!-- Col 0: Customer Info -->
                <ColumnDefinition Width="*"/> <!-- Col 1: Email Type -->
                <ColumnDefinition Width="*"/> <!-- Col 2: Ticket Details -->
            </Grid.ColumnDefinitions>

            <!-- Menu -->
            <Menu DockPanel.Dock="Top" Background="#FFFFFF" Foreground="#000000" FontFamily="Segoe UI" FontSize="11">
                    <MenuItem Header="Menu" FontWeight="Bold">
                        <MenuItem Header="Open Dir / File">
                            <MenuItem Header="Open File Explorer" Name="FileExplorerMenu"/>
                        </MenuItem>
                        <Separator/>
                        <MenuItem Header="App Info">
                            <MenuItem Header="About rtts app" Name="AboutMenu"/>
                            <MenuItem Header="Check for Update" Name="UpdateMenu"/>
                            <MenuItem Header="Uninstall rtts app" Name="UninstallMenu"/>
                        </MenuItem>
                        <Separator/>
                        <MenuItem Header="Reload App" Name="ReloadMenu"/>
                        <MenuItem Header="Exit" Name="ExitMenu"/>
                    </MenuItem>
                </Menu>

            <!-- Title -->
            <TextBlock Text="Email Generator" Grid.Row="1" Grid.ColumnSpan="3" HorizontalAlignment="Center" 
                       FontSize="38" FontWeight="Bold" Foreground="Red" Margin="0,10,0,20">
                <TextBlock.Effect>
                    <DropShadowEffect Color="Gray" Direction="315" ShadowDepth="4" Opacity="0.5" />
                </TextBlock.Effect>
            </TextBlock>

            <!-- Right Column - Customer Info (Col 0) -->
            <GroupBox Header="Customer Information" Grid.Row="2" Grid.Column="0" Padding="10" Background="#81b0b6">
                <StackPanel>
                    <Label Content="Customer Name:"/>
                    <TextBox Name="cxb_name" Margin="0,2"/>
                    <Label Content="Customer CID Number:"/>
                    <TextBox Name="cxid_num" Margin="0,2"/>
                    <Label Content="Customer Location:"/>
                    <TextBox Name="site_add" Margin="0,2,0,15"/>
                    <Button Name="BtnSubmit" 
                        Content="Generate 📧" 
                        FontSize="22" 
                        FontWeight="Bold" 
                        Background="#0683ff" 
                        Foreground="White" 
                        Width="240" 
                        Height="60" 
                        Margin="0,0,0,8" 
                        VerticalContentAlignment="Center" 
                        HorizontalContentAlignment="Center"/>
                </StackPanel>
            </GroupBox>

            <!-- Middle Column - Email Type (Col 1) -->
            <GroupBox Header="Email Type &amp; Subject" Grid.Row="2" Grid.Column="1" Padding="10" Background="#f0f3c3">
                <StackPanel>
                    <Label Content="Select Recipient:"/>
                    <ComboBox Name="eBox" Margin="0,0,0,5">
                    </ComboBox>
                    <Label Content="Select Email Type:"/>
                    <ComboBox Name="tyBox" Margin="0,0,0,10">
                    </ComboBox> 
                    <Label Content="State Issue Raised:"/>
                    <ComboBox Name="pBox" Margin="0,0,0,10">
                        <ComboBoxItem Content="[OOS]-HARD DOWN" />
                        <ComboBoxItem Content="[LOR]-Redundancy" />
                        <ComboBoxItem Content="LINK FLAP" />
                        <ComboBoxItem Content="FRAME LOSS" />
                        <ComboBoxItem Content="Technical Support" />
                        <ComboBoxItem Content="Request" />
                    </ComboBox> 
                    <Label Content="Service Type:"/>
                    <ComboBox Name="serviceType" Margin="0,0,0,5">
                        <ComboBoxItem Content="Ticket Update || UCR Update" />
                        <ComboBoxItem Content="PTP-Commercial Internet" />
                        <ComboBoxItem Content="Dark Fiber" />
                        <ComboBoxItem Content="DNS" />
                        <ComboBoxItem Content="DS3" />
                        <ComboBoxItem Content="Ethernet / DIA" />
                        <ComboBoxItem Content="FTTT" />
                        <ComboBoxItem Content="Monitor / Surveillance" />
                        <ComboBoxItem Content="OC12" />
                        <ComboBoxItem Content="OC192" />
                        <ComboBoxItem Content="OC3" />
                        <ComboBoxItem Content="OC48" />
                        <ComboBoxItem Content="Optical Transport Service" />
                        <ComboBoxItem Content="Turn-Up" />
                        <ComboBoxItem Content="VOIP" />
                        <ComboBoxItem Content="Wave" />
                    </ComboBox>
                </StackPanel>
            </GroupBox>

            <!-- Left Column - Ticket Details (Col 2) -->
            <GroupBox Header="Ticket Details" Grid.Row="2" Grid.Column="2" Padding="10" Background="#a7f7a7">
                <StackPanel>
                    <Label Content="Ticket Created?"/>
                    <StackPanel Orientation="Horizontal" Margin="0,0,0,10">
                        <RadioButton Name="RadYes" Content="Yes" Margin="0,0,15,0" />
                        <RadioButton Name="RadNo" Content="No"  IsChecked="True" Margin="0,0,15,0" />
                    </StackPanel>
                    <StackPanel Name="TicketPanel" Visibility = "Collapsed">
                        <Label Content="External Ticket #:"/>
                        <TextBox Name="ext_ticket" Margin="0,0,0,5"/>
                        <Label Content="Internal Ticket #:"/>
                        <TextBox Name="int_ticket" Margin="0,0,0,5"/>
                    </StackPanel>
                    <StackPanel Name= "rttslogo">
                            <Image Source="$FileDir\.icons\logo.png" Width="220" Height="170" Margin="60,0,60,0"/>
                    </StackPanel>
                </StackPanel>
            </GroupBox>
        </Grid>
    </Window>
"@
# 3. Load UI and Map Controls
$reader = New-Object System.Xml.XmlNodeReader $xaml
$eform = [Windows.Markup.XamlReader]::Load($reader)

#---------------------------------
# 1. FIND and assign ALL UI elements
$menuFileExplorer = $eform.FindName("FileExplorerMenu")
$menuAbout        = $eform.FindName("AboutMenu")
$menuUpdate       = $eform.FindName("UpdateMenu")
$menuUninstall    = $eform.FindName("UninstallMenu")
$menuReload       = $eform.FindName("ReloadMenu")
$menuExit         = $eform.FindName("ExitMenu")

 # ===== MENU CLICK HANDLERS =====
    if ($menuFileExplorer) {
        $menuFileExplorer.Add_Click({
            [System.Windows.MessageBox]::Show("Opening Ticket Log Folder/ Working Directory", "Info", [System.Windows.MessageBoxButton]::OK, [System.Windows.MessageBoxImage]::Information) | Out-Null
        explorer /select, $savDir
        })
    }
    
    if ($menuAbout) {
        $menuAbout.Add_Click({
            [System.Windows.MessageBox]::Show($aboutText, "About RTTS App", [System.Windows.MessageBoxButton]::OK, [System.Windows.MessageBoxImage]::Information) | Out-Null
        })
    }
    
    if ($menuUpdate) {
        $menuUpdate.Add_Click({
            [System.Windows.MessageBox]::Show("Checking for updates...`nVisiting GitHub repository", "Update Check", [System.Windows.MessageBoxButton]::OK, [System.Windows.MessageBoxImage]::Information) | Out-Null
            Start-Process "https://github.com/rttsja/rtts-apps.git"
        })
    }
    
    if ($menuUninstall) {
        $menuUninstall.Add_Click({
            $result = [System.Windows.MessageBox]::Show("Are you sure you want to uninstall RTTS App?", "Confirm Uninstall", [System.Windows.MessageBoxButton]::YesNo, [System.Windows.MessageBoxImage]::Question)
            if ($result -eq "Yes") {
                $eform.Close()
                uninstall_rtts}
        })
    }
    
    if ($menuReload) {
        $menuReload.Add_Click({
                $eform.DialogResult = [System.Windows.Forms.DialogResult]::OK
                $eform.Close()
                $eform.ShowDialog()
                $eform.Dispose()
                reload_form}.GetNewClosure()) # This captures the environment so it doesn't die with $eform
}
    
    if ($menuExit) {
        $menuExit.Add_Click({
            $eform.Close()
        })
    }

$e = @{} # Initialize hash table for controls
$e.eBox           = $eform.FindName("eBox")
$e.pBox           = $eform.FindName("pBox")
$e.tyBox          = $eform.FindName("tyBox")
$e.int_ticket     = $eform.FindName("int_ticket")
$e.ext_ticket     = $eform.FindName("ext_ticket")
$e.cxb_name       = $eform.FindName("cxb_name")
$e.cxid_num       = $eform.FindName("cxid_num")
$e.site_add       = $eform.FindName("site_add")
$e.servtyp        = $eform.FindName("serviceType")

$BtnSubmit        = $eform.FindName("BtnSubmit")
$RadNo            = $eform.FindName("RadNo")
$RadYes           = $eform.FindName("RadYes")
$TicketPanel      = $eform.FindName("TicketPanel")
$rttslogo         = $eform.FindName("rttslogo")

#---------------------------------
## 2. Define the arrays
$eArray    = @("[ISP] - [OSP] - [IP OPS]", "Type II Provider", "NL2 / NL3", "Customer")
$custArray = @("Type II Outage >> Client", "Ticket Created Advisory", "Site Access Request", "No Fault Found","Major Outage Advisory >> Client")
$dispArray = @("Dispatch Request", "Dispatch Update")
$ty2Array  = @("Type II Update Request")
$nl2Array  = @("UTT | UCR Update Request")

# Populate the primary ComboBox
$eArray | ForEach-Object { [void]$e.eBox.Items.Add($_) }

# 3. SelectionChanged Event Listener (Fixed Selection Handling)
$e.eBox.add_SelectionChanged({
    $e.tyBox.Items.Clear()
    
    if ($null -eq $e.eBox.SelectedItem) { return }
    
    # Correctly retrieve text from ComboBoxItem
    $selectedValue = ($e.eBox.SelectedItem.Content -as [string])
    if (!$selectedValue) { $selectedValue = $e.eBox.SelectedItem.ToString() }

    switch ($selectedValue) {
        "[ISP] - [OSP] - [IP OPS]" { $dispArray | ForEach-Object { [void]$e.tyBox.Items.Add($_) } }
        "Type II Provider"         { $ty2Array  | ForEach-Object { [void]$e.tyBox.Items.Add($_) } }
        "NL2 / NL3"                { $nl2Array  | ForEach-Object { [void]$e.tyBox.Items.Add($_) } }
        "Customer"                 { $custArray | ForEach-Object { [void]$e.tyBox.Items.Add($_) } }
    }
    
    if ($e.tyBox.Items.Count -gt 0) { 
        $e.tyBox.SelectedIndex = 0 
    }
})

#------------------------------------

#---------------------------------
# 4. Visibility Handlers
$RadNo.Add_Checked({ 
    $TicketPanel.Visibility = "Collapsed" 
    $rttslogo.Visibility = "Visible" 
})
$RadYes.Add_Checked({ 
    $TicketPanel.Visibility = "Visible" 
    $rttslogo.Visibility = "Collapsed" 
})

#--------------------------
$BtnSubmit.Add_Click({
    try {
        if ($null -eq $e.tyBox.SelectedItem) {
            [System.Windows.MessageBox]::Show("Please select a Request Type.", "Selection Required")
            return
        }

        # CAPTURE: Map UI elements to variables (using .Text or .Content safely)
        $global:SelectedType = ($e.tyBox.SelectedItem.Content -as [string])
        if (!$global:SelectedType) { $global:SelectedType = $e.tyBox.SelectedItem.ToString() }
        
        # Capture remaining fields
        $global:cxb_name = $e.cxb_name.Text 
        $global:eBox           = $e.eBox.Text
        $global:selcp           = $e.pBox.Text
        $global:tyBox          = $e.tyBox.Text
        $global:ccr_num     = $e.int_ticket.Text
        $global:e_tk_num     = $e.ext_ticket.Text
        $global:cxid_num       = $e.cxid_num.Text
        $global:site_add       = $e.site_add.Text
        $global:cxb_net_type        = $e.servtyp.Text
        # EXECUTION: Ensure switch matches the variable captured above
        switch ($global:SelectedType) {
            "Dispatch Request"                { dispatch_req }
            "Dispatch Update"                 { dispatch_upd_req }
            "UTT | UCR Update Request"        { nl2_utt_ucr_upd }
            "Type II Outage >> Client"        { t2_out_ad }
            "Type II Update Request"          { t2_up_req }
            "Ticket Created Advisory"         { ccr_ad }
            "No Fault Found"                  { no_fault }
            "Site Access Request"             { cxb_site_acc }
            "Major Outage Advisory >> Client" { cxb_mo_ad }
            Default { [System.Windows.MessageBox]::Show("No function for: $($global:SelectedType)") ; return }
        }

        # FILE RETRIEVAL
        $cleanName = ($Global:SelectedName -replace '[\\/\:\*\?\"\<\>\|]', '')
        $searchPattern = "*$cleanName*.docx"
        
        $latestFile = Get-ChildItem -Path $script:savDir -Filter $searchPattern -Recurse -ErrorAction SilentlyContinue | 
                      Sort-Object LastWriteTime -Descending | Select-Object -First 1

        if ($latestFile) { 
            Start-Process $latestFile.FullName 
            $eform.Close() 
        } else { 
            [System.Windows.MessageBox]::Show("Draft file not found in: $($script:savDir)", "File Error")
        }
    } catch {
        [System.Windows.MessageBox]::Show("Error: $($_.Exception.Message)", "System Error")
    }
})

$eform.ShowDialog() | Out-Null

}
###.................>> LAUNCH ZONE <-----------------###
launchHOME 

